// Check if FFmpeg is installed
try {
  const { execSync } = require('child_process');
  const result = execSync('ffmpeg -version 2>&1', { encoding: 'utf8', stdio: ['pipe', 'pipe', 'pipe'] });
  return [{ json: { stdout: 'FFmpeg is installed', installed: true } }];
} catch (error) {
  return [{ json: { stdout: '', installed: false, error: error.message } }];
}

