// Generate timestamp for expires
for (const item of $input.all()) {
  const now = new Date();
  const tomorrow = new Date(now.getTime() + 24 * 60 * 60 * 1000);
  item.json.timestamp = tomorrow.toISOString();
}
return $input.all();
